blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie poznasz <strong>cztery podstawowe typy zdań w języku angielskim</strong>, ich budowę i najważniejsze różnice.",
    "rules": [
        {
            "label": "Affirmative",
            "color": "emerald",
            "text": "<strong>zdanie twierdzące</strong> — podaje informację lub fakt:",
            "example": "She reads books."
        },
        {
            "label": "Negative",
            "color": "rose",
            "text": "<strong>zdanie przeczące</strong> — zaprzecza informacji:",
            "example": "She does not read books."
        },
        {
            "label": "Interrogative",
            "color": "blue",
            "text": "<strong>zdanie pytające</strong> — zadaje pytanie:",
            "example": "Does she read books?"
        },
        {
            "label": "Imperative",
            "color": "amber",
            "text": "<strong>zdanie rozkazujące</strong> — wyraża polecenie, prośbę albo radę:",
            "example": "Read this book!"
        }
    ]
}

{
    "title": "1. Przegląd czterech typów zdań",
    "intro": "Zdania w angielskim dzielimy według celu wypowiedzi na cztery główne grupy:",
    "items": [
        {
            "label": "Affirmative",
            "title": "Twierdzące",
            "subtitle": "Przekazują fakt albo informację: She works here."
        },
        {
            "label": "Negative",
            "title": "Przeczące",
            "subtitle": "Zaprzeczają faktowi albo czynności: She does not work here."
        },
        {
            "label": "Interrogative",
            "title": "Pytające",
            "subtitle": "Służą do zadawania pytań: Does she work here?"
        },
        {
            "label": "Imperative",
            "title": "Rozkazujące",
            "subtitle": "Wyrażają polecenie, prośbę albo radę: Work harder!"
        }
    ]
}

{
    "title": "2. Zdania twierdzące",
    "sections": [
        {
            "label": "Budowa",
            "color": "emerald",
            "description": "Zdanie twierdzące przekazuje fakt. Najczęstszy szyk to <strong>Subject + Verb + Object</strong>.",
            "examples": [
                {
                    "en": "I like coffee.",
                    "ua": "Lubię kawę."
                },
                {
                    "en": "She works at a hospital.",
                    "ua": "Ona pracuje w szpitalu."
                },
                {
                    "en": "They have two children.",
                    "ua": "Mają dwoje dzieci."
                }
            ]
        },
        {
            "label": "Z to be",
            "color": "sky",
            "description": "Z czasownikiem <strong>to be</strong> używamy schematu <strong>Subject + am / is / are + complement</strong>.",
            "examples": [
                {
                    "en": "I am a student.",
                    "ua": "Jestem uczniem."
                },
                {
                    "en": "She is happy.",
                    "ua": "Ona jest szczęśliwa."
                },
                {
                    "en": "They are at home.",
                    "ua": "Oni są w domu."
                }
            ]
        },
        {
            "label": "Interpunkcja",
            "color": "amber",
            "description": "Zdanie twierdzące kończy się kropką.",
            "examples": [
                {
                    "en": "The sun rises in the east.",
                    "ua": "Słońce wschodzi na wschodzie."
                }
            ]
        }
    ]
}

{
    "title": "3. Zdania przeczące",
    "sections": [
        {
            "label": "Ze zwykłym czasownikiem",
            "color": "emerald",
            "description": "Do przeczenia przy zwykłych czasownikach używamy <strong>do / does / did + not</strong>.",
            "examples": [
                {
                    "en": "I do not like coffee.",
                    "ua": "Nie lubię kawy."
                },
                {
                    "en": "She does not work here.",
                    "ua": "Ona tu nie pracuje."
                },
                {
                    "en": "They did not come yesterday.",
                    "ua": "Oni nie przyszli wczoraj."
                }
            ]
        },
        {
            "label": "Z to be",
            "color": "sky",
            "description": "Przy czasowniku <strong>to be</strong> dodajemy <strong>not</strong> bezpośrednio po formie czasownika.",
            "examples": [
                {
                    "en": "I am not tired.",
                    "ua": "Nie jestem zmęczony."
                },
                {
                    "en": "She is not at home.",
                    "ua": "Jej nie ma w domu."
                },
                {
                    "en": "They are not ready.",
                    "ua": "Oni nie są gotowi."
                }
            ]
        },
        {
            "label": "Formy skrócone",
            "color": "amber",
            "description": "W codziennej mowie bardzo często używamy skrótów.",
            "examples": [
                {
                    "en": "don't = do not",
                    "ua": "I don't like it."
                },
                {
                    "en": "doesn't = does not",
                    "ua": "She doesn't know."
                },
                {
                    "en": "isn't = is not",
                    "ua": "He isn't here."
                },
                {
                    "en": "aren't = are not",
                    "ua": "They aren't coming."
                }
            ]
        }
    ]
}

{
    "title": "4. Zdania pytające",
    "sections": [
        {
            "label": "Yes / No questions",
            "color": "emerald",
            "description": "W pytaniach ogólnych używamy zwykle schematu <strong>Do / Does / Did + Subject + Verb?</strong>",
            "examples": [
                {
                    "en": "Do you like coffee?",
                    "ua": "Lubisz kawę?"
                },
                {
                    "en": "Does she work here?",
                    "ua": "Czy ona tu pracuje?"
                },
                {
                    "en": "Did they come yesterday?",
                    "ua": "Czy oni przyszli wczoraj?"
                }
            ]
        },
        {
            "label": "Pytania z to be",
            "color": "sky",
            "description": "W pytaniach z <strong>to be</strong> forma czasownika przechodzi przed podmiot.",
            "examples": [
                {
                    "en": "Are you ready?",
                    "ua": "Czy jesteś gotowy?"
                },
                {
                    "en": "Is she a doctor?",
                    "ua": "Czy ona jest lekarką?"
                },
                {
                    "en": "Were they at the party?",
                    "ua": "Czy oni byli na imprezie?"
                }
            ]
        },
        {
            "label": "Wh-questions",
            "color": "amber",
            "description": "Pytania szczegółowe zaczynają się od <strong>what, where, when, why, who, how</strong> i zwykle wymagają odpowiedniego szyku pytania.",
            "examples": [
                {
                    "en": "What do you do?",
                    "ua": "Czym się zajmujesz?"
                },
                {
                    "en": "Where does she live?",
                    "ua": "Gdzie ona mieszka?"
                },
                {
                    "en": "Why are you late?",
                    "ua": "Dlaczego się spóźniłeś?"
                },
                {
                    "en": "How did they get there?",
                    "ua": "Jak oni tam dotarli?"
                }
            ],
            "note": "Zdanie pytające kończy się znakiem zapytania."
        }
    ]
}

{
    "title": "5. Zdania rozkazujące",
    "sections": [
        {
            "label": "Budowa",
            "color": "emerald",
            "description": "Zdanie rozkazujące zaczyna się od <strong>czasownika w formie podstawowej</strong> i zwykle nie ma wyrażonego podmiotu.",
            "examples": [
                {
                    "en": "Open the door.",
                    "ua": "Otwórz drzwi."
                },
                {
                    "en": "Come here.",
                    "ua": "Podejdź tutaj."
                },
                {
                    "en": "Be quiet.",
                    "ua": "Bądź cicho."
                }
            ]
        },
        {
            "label": "Forma przecząca",
            "color": "sky",
            "description": "Aby utworzyć zakaz lub przeczenie, używamy <strong>Don't + Verb</strong>.",
            "examples": [
                {
                    "en": "Don't touch that!",
                    "ua": "Nie dotykaj tego!"
                },
                {
                    "en": "Don't be late.",
                    "ua": "Nie spóźnij się."
                },
                {
                    "en": "Don't forget your keys.",
                    "ua": "Nie zapomnij kluczy."
                }
            ]
        },
        {
            "label": "Formy uprzejme",
            "color": "amber",
            "description": "Uprzejmość budujemy przez <strong>please</strong>, a propozycje często przez <strong>let's</strong>.",
            "examples": [
                {
                    "en": "Please sit down.",
                    "ua": "Proszę, usiądź."
                },
                {
                    "en": "Please be patient.",
                    "ua": "Proszę, bądź cierpliwy."
                },
                {
                    "en": "Let's go to the cinema.",
                    "ua": "Chodźmy do kina."
                },
                {
                    "en": "Let's start the meeting.",
                    "ua": "Zacznijmy spotkanie."
                }
            ],
            "note": "Zdanie rozkazujące może kończyć się kropką albo wykrzyknikiem."
        }
    ]
}

{
    "title": "6. Tabela porównawcza struktur",
    "intro": "Najprostsze wzory czterech typów zdań:",
    "rows": [
        {
            "en": "Affirmative",
            "ua": "twierdzące",
            "note": "S + V + O → She reads books."
        },
        {
            "en": "Negative",
            "ua": "przeczące",
            "note": "S + do / does + not + V → She doesn't read."
        },
        {
            "en": "Interrogative",
            "ua": "pytające",
            "note": "Do / Does + S + V? → Does she read?"
        },
        {
            "en": "Imperative",
            "ua": "rozkazujące",
            "note": "V + O → Read this book!"
        }
    ],
    "warning": "📌 W pytaniach i przeczeniach bardzo często potrzebujesz czasownika pomocniczego: <strong>do / does / did</strong>."
}

{
    "title": "7. Interpunkcja w różnych typach zdań",
    "intro": "Każdy typ zdania ma najczęściej swój typowy znak końcowy:",
    "rows": [
        {
            "en": "Affirmative",
            "ua": "twierdzące",
            "note": "kropka: She is a teacher."
        },
        {
            "en": "Negative",
            "ua": "przeczące",
            "note": "kropka: She is not a teacher."
        },
        {
            "en": "Interrogative",
            "ua": "pytające",
            "note": "znak zapytania: Is she a teacher?"
        },
        {
            "en": "Imperative",
            "ua": "rozkazujące",
            "note": "kropka albo wykrzyknik: Be quiet. / Be quiet!"
        }
    ]
}

{
    "title": "8. Typowe błędy polskich uczących się",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Brak czasownika pomocniczego w przeczeniu.",
            "wrong": "She not likes coffee.",
            "right": "✅ <span class=\"font-mono\">She does not like coffee.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Brak czasownika pomocniczego w pytaniu.",
            "wrong": "You like coffee?",
            "right": "✅ <span class=\"font-mono\">Do you like coffee?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Końcówka -s po does.",
            "wrong": "Does she likes coffee?",
            "right": "✅ <span class=\"font-mono\">Does she like coffee?</span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Wyrażony podmiot w zdaniu rozkazującym bez potrzeby.",
            "wrong": "You open the door!",
            "right": "✅ <span class=\"font-mono\">Open the door!</span>"
        }
    ]
}

{
    "title": "10. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Rozpoznaj typ zdania",
    "select_intro": "Wybierz, do jakiej grupy należy zdanie.",
    "selects": [
        {
            "label": "She works at a bank. (Affirmative / Negative / Interrogative / Imperative)",
            "prompt": "Jaki to typ?"
        },
        {
            "label": "Do you speak English? (Affirmative / Negative / Interrogative / Imperative)",
            "prompt": "Jaki to typ?"
        },
        {
            "label": "Close the window. (Affirmative / Negative / Interrogative / Imperative)",
            "prompt": "Jaki to typ?"
        },
        {
            "label": "I don't understand. (Affirmative / Negative / Interrogative / Imperative)",
            "prompt": "Jaki to typ?"
        }
    ],
    "options": [
        "Affirmative",
        "Negative",
        "Interrogative",
        "Imperative"
    ],
    "input_title": "Ćwiczenie 2. Przekształć zdanie",
    "input_intro": "Zamień zdanie twierdzące na inną formę.",
    "inputs": [
        {
            "before": "She likes music. → Negative:",
            "after": "→"
        },
        {
            "before": "She likes music. → Question:",
            "after": "→"
        },
        {
            "before": "You are quiet. → Imperative:",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw niepoprawne zdanie.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "She not like coffee.",
            "example_target": "She doesn't like coffee."
        },
        {
            "original": "1. Does he likes football?",
            "placeholder": "Popraw błąd"
        },
        {
            "original": "2. You be quiet!",
            "placeholder": "Popraw błąd"
        }
    ]
}

